import { useState, useEffect } from 'react';
import ProdutoService from '../services/produtoService';

export const useProdutos = () => {
  const [produtos, setProdutos] = useState([]);
  const [carregando, setCarregando] = useState(false);
  const [erro, setErro] = useState(null);

  // Carregar produtos do banco de dados
  const carregarProdutos = async () => {
    setCarregando(true);
    setErro(null);

    try {
      // Carregar produtos do banco IndexedDB
      const resultadoDB = await ProdutoService.listarProdutos();

      // Carregar produtos originais do data/produtos.js
      const produtosOriginais = await import('../data/produtos').then(module => module.produtos);

      let todosProdutos = [];

      // Adicionar produtos originais
      todosProdutos = produtosOriginais.map(produto => ({
        ...produto,
        id: `original-${produto.nome}`,
        isOriginal: true
      }));

      // Adicionar produtos cadastrados no banco
      if (resultadoDB.success) {
        const produtosDB = resultadoDB.data.map(produto => ({
          ...produto,
          isOriginal: false
        }));
        todosProdutos = [...todosProdutos, ...produtosDB];
      }

      setProdutos(todosProdutos);
    } catch (error) {
      console.error('Erro ao carregar produtos:', error);
      setErro('Erro ao carregar produtos');
    } finally {
      setCarregando(false);
    }
  };

  // Adicionar novo produto
  const adicionarProduto = async (produtoData) => {
    setCarregando(true);
    setErro(null);

    try {
      const resultado = await ProdutoService.adicionarProduto(produtoData);

      if (resultado.success) {
        await carregarProdutos(); // Recarregar lista
        return { success: true };
      } else {
        setErro(resultado.error);
        return { success: false, error: resultado.error };
      }
    } catch (error) {
      const mensagemErro = 'Erro ao adicionar produto';
      setErro(mensagemErro);
      return { success: false, error: mensagemErro };
    } finally {
      setCarregando(false);
    }
  };

  // Excluir produto
  const excluirProduto = async (id) => {
    setCarregando(true);
    setErro(null);

    try {
      // Só pode excluir produtos que não são originais
      if (id.startsWith('original-')) {
        return { success: false, error: 'Não é possível excluir produtos originais' };
      }

      const resultado = await ProdutoService.excluirProduto(id);

      if (resultado.success) {
        await carregarProdutos(); // Recarregar lista
        return { success: true };
      } else {
        setErro(resultado.error);
        return { success: false, error: resultado.error };
      }
    } catch (error) {
      const mensagemErro = 'Erro ao excluir produto';
      setErro(mensagemErro);
      return { success: false, error: mensagemErro };
    } finally {
      setCarregando(false);
    }
  };

  // Carregar produtos ao montar o hook
  useEffect(() => {
    carregarProdutos();
  }, []);

  return {
    produtos,
    carregando,
    erro,
    carregarProdutos,
    adicionarProduto,
    excluirProduto
  };
};
